"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

// ---------- Root context ----------

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
  steps: React.MutableRefObject<string[]>
  registerStep: (value: string) => void
  unregisterStep: (value: string) => void
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a Stepper.")
  }
  return context
}

// ---------- Item context ----------

type StepperItemContextValue = {
  value: string
  state: "active" | "completed" | "pending"
  disabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a StepperItem.")
  }
  return context
}

// ---------- Stepper (root) ----------

interface StepperProps extends React.ComponentProps<"div"> {
  value: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  value,
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const steps = React.useRef<string[]>([])

  const registerStep = React.useCallback((stepValue: string) => {
    if (!steps.current.includes(stepValue)) {
      steps.current = [...steps.current, stepValue]
    }
  }, [])

  const unregisterStep = React.useCallback((stepValue: string) => {
    steps.current = steps.current.filter((s) => s !== stepValue)
  }, [])

  return (
    <StepperContext.Provider
      value={{
        value,
        onValueChange: onValueChange ?? (() => {}),
        orientation,
        steps,
        registerStep,
        unregisterStep,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex data-horizontal:flex-row data-horizontal:items-start data-vertical:flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ---------- StepperItem ----------

interface StepperItemProps extends React.ComponentProps<"div"> {
  value: string
  disabled?: boolean
}

function StepperItem({
  value,
  disabled = false,
  className,
  ...props
}: StepperItemProps) {
  const {
    value: activeValue,
    steps,
    registerStep,
    unregisterStep,
  } = useStepper()

  React.useLayoutEffect(() => {
    registerStep(value)
    return () => {
      unregisterStep(value)
    }
  }, [value, registerStep, unregisterStep])

  const activeIndex = steps.current.indexOf(activeValue)
  const itemIndex = steps.current.indexOf(value)
  const state: "active" | "completed" | "pending" =
    itemIndex === activeIndex
      ? "active"
      : itemIndex < activeIndex
        ? "completed"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ value, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "cn-stepper-item group/stepper-item flex flex-col group-data-horizontal/stepper:items-center",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ---------- StepperTrigger ----------

function StepperTrigger({
  className,
  onClick,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, state, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      disabled={disabled}
      onClick={(e) => {
        onValueChange(value)
        onClick?.(e)
      }}
      className={cn(
        "cn-stepper-trigger inline-flex cursor-pointer items-center gap-2 outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    />
  )
}

// ---------- StepperTitle ----------

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("cn-stepper-title text-sm font-medium", className)}
      {...props}
    />
  )
}

// ---------- StepperDescription ----------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-xs text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------- StepperSeparator ----------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "cn-stepper-separator shrink-0 bg-border group-data-horizontal/stepper:h-px group-data-horizontal/stepper:flex-1 group-data-horizontal/stepper:self-center group-data-vertical/stepper:ms-3 group-data-vertical/stepper:h-4 group-data-vertical/stepper:w-px",
        className
      )}
      {...props}
    />
  )
}

// ---------- StepperContent ----------

function StepperContent({ className, ...props }: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  if (state !== "active") return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("cn-stepper-content", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}

