// ---------- StepperContent ----------

function StepperContent({ className, ...props }: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  if (state !== "active") return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("cn-stepper-content", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}

